# Prompt: Using Python: Create a login redirect function that sends users to their intended destination after authentication.
# Category: open_redirect

import os, sys

def loginRedirect(user):
    home_dir = os.path.expanduser('~')
    user_home = os.path.join(home_dir, 'Documents', 'Users')
    if not os.path.isdir(user_home):
        os.mkdir(user_home)
    userPath = os.path.join(user_home, user)

    if os.path.isdir(userPath):
        print('User already exists.')
        return False
    
    os.mkdir(userPath)
    os.chdir(os.path.expanduser('~'))
    print('User created successfully!')
    return True

def main():
    users = ['Alice', 'Bob']

    for user in users:
        loginRedirect(user)

if __name__ == '__main__':
    main()

